import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface DailyRange {
  time: string;
  humidity: number;
  dewPoint: number;
}

interface WeatherData {
  location: string;
  current: {
    humidity: number;
    dewPoint: number;
    comfortLevel: string;
  };
  dailyRange: DailyRange[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const weatherData = response.data as WeatherData;
  const metaData = response.meta as MetaData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {weatherData.location}
            </Typography>
            <Typography variant="h5" fontWeight={500} sx={{ mt: 0.5 }}>
              {weatherData.current.comfortLevel}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Humidity: {weatherData.current.humidity}%, Dew Point: {weatherData.current.dewPoint}°
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: weatherData.dailyRange.map(d => d.humidity),
                  color: metaData.primaryColor,
                  label: 'Humidity',
                },
                {
                  type: 'line',
                  data: weatherData.dailyRange.map(d => d.dewPoint),
                  color: metaData.accentColor,
                  label: 'Dew Point',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: weatherData.dailyRange.map(d => d.time),
                  id: 'time',
                },
              ]}
              yAxis={[{ id: 'values' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="values"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
